class _ExampleHomePageState extends State<ExampleHomePage> {
  final usernameController = TextEditingController();
  final passwordController = TextEditingController();
  final client = LoggingHttpClient();

  @override
  void initState() {
    super.initState();
    UserInteractionLogger.screenView('ExampleHomePage');
  }

  Future<void> _login() async {
    final username = usernameController.text;
    final password = passwordController.text;

    AuthLogger.loginStart(username: username, password: password);

    try {
      final response = await client.post(
        Uri.parse('https://example.com/login'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          'username': username,
          'password': password,
        }),
      );

      if (response.statusCode == 200) {
        final token = 'example-token';
        AuthLogger.loginSuccess(username: username, token: token);
      } else {
        AuthLogger.loginFailure(
          username: username,
          error: 'Login failed: ${response.statusCode}',
        );
      }
    } catch (e, st) {
      AuthLogger.loginFailure(username: username, error: e, stackTrace: st);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Logging Example')),
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          children: [
            LoggingTextField(
              label: 'Username',
              controller: usernameController,
            ),
            LoggingTextField(
              label: 'Password',
              controller: passwordController,
              obscureText: true,
            ),
            const SizedBox(height: 16),
            LoggingButton(
              label: 'Login',
              onPressed: _login,
              metadata: {'screen': 'ExampleHomePage'},
            ),
          ],
        ),
      ),
    );
  }

  @override
  void dispose() {
    usernameController.dispose();
    passwordController.dispose();
    client.close();
    super.dispose();
  }
}

